const body = $input.item.json.body;
const { doc_type, doc_number, username, tab_id } = body || {};
if (!doc_type || !doc_number || !username) {
  return { json: { _error: true, message: '缺少参数: doc_type, doc_number, username' } };
}
return { json: { _error: false, doc_type, doc_number, username, tab_id: tab_id || '' } };

// 两步走锁判定 - 4种情形
const row = $input.first().json;        // SELECT结果（行不存在时为空对象）
const req = $('Validate Acquire').first().json;  // 请求参数
const now = Date.now();

const lockedBy = row && row.locked_by ? row.locked_by : null;
const lockedSession = row && row.locked_session ? row.locked_session : null;
const lockedAt = row && row.locked_at ? new Date(row.locked_at).getTime() : 0;
const expired = lockedAt > 0 && (now - lockedAt) > 30 * 60 * 1000;

// 情形1: 行不存在 / 无锁 / 已超时 → 允许加锁
if (!lockedBy || expired) {
  return { json: { _allow: true, ...req } };
}
// 情形2: 同账号同session（页面刷新续租） → 允许
if (lockedBy === req.username && lockedSession === req.tab_id) {
  return { json: { _allow: true, ...req } };
}
// 情形3: 同账号不同session（同账号另一浏览器） → 拒绝，给出明确提示
if (lockedBy === req.username) {
  return { json: { _allow: false, locked_by: lockedBy, message: '您在另一个窗口已打开此单据，请关闭其他窗口后重试' } };
}
// 情形4: 不同账号 → 拒绝
return { json: { _allow: false, locked_by: lockedBy, message: '该单据正由 [' + lockedBy + '] 处理中，您暂时无法编辑' } };

const body = $input.item.json.body;
const { doc_type, doc_number, username, tab_id } = body || {};
if (!doc_type || !doc_number || !username) {
  return { json: { _error: true, message: '缺少参数' } };
}
return { json: { _error: false, doc_type, doc_number, username, tab_id: tab_id || '' } };

const row = $input.first().json;
const lockedBy = row.locked_by || null;
const lockedAt = row.locked_at || null;
return { json: { success: true, locked: !!lockedBy, locked_by: lockedBy, locked_at: lockedAt } };
